 // run lock already held by the caller.
 func syncAfterRepin(cmd *cobra.Command, rc *runtimeContext, scopeRoot, manifestPath string, userScope bool, now time.Time) error {
 	scope := "project"
 	if userScope {
 		scope = "user"
