 	prep, err := prepareScope(cmd.Context(), rc, scopeRoot, manifestPath, scope, now)
 	if err != nil {
 		return err
 	}
 	defer prep.Close()

 	req := prep.Request
 	req.Options = engine.Options{
 		Now:         func() time.Time { return now },
